```typescript
/**
 * Set a value in sessionStorage. Silently fails on SecurityError
 * (sandboxed iframes) or QuotaExceededError.
 */
export const setSessionStorage = (key: string, value: string): void => {
  try {
    sessionStorage.setItem(key, value);
  } catch {
    // SecurityError in sandboxed iframes, QuotaExceededError if full
  }
};
```

