Edit platform/browser-extension/src/side-panel/components/ReturningUserEmptyState.tsx. Add a state variable for the confirmation flow:

```typescript
const [confirming, setConfirming] = useState(false);
const timerRef = useRef<number | null>(null);

const handleClick = () => {
  if (confirming) {
    // Second click — perform reset
    if (timerRef.current) clearTimeout(timerRef.current);
    onResetOnboarding();
  } else {
    // First click — enter confirmation mode
    setConfirming(true);
    timerRef.current = window.setTimeout(() => setConfirming(false), 3000);
  }
};

// Cleanup timer on unmount
useEffect(() => () => { if (timerRef.current) clearTimeout(timerRef.current); }, []);
```

Render: `<button onClick={handleClick}>{confirming ? 'Click again to confirm' : 'Show setup guide'}</button>`
